import React, { useEffect, useState } from 'react';
import axios from 'axios';
import Slider from 'react-slick';
import 'slick-carousel/slick/slick.css';
import 'slick-carousel/slick/slick-theme.css';
import '../Styles/Global.css';

const Home = () => {
  const [featuredPlants, setFeaturedPlants] = useState([]);
  const [categories, setCategories] = useState([]);

  useEffect(() => {
    const fetchFeatured = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/admin/products/featured');
        setFeaturedPlants(res.data);
      } catch (err) {
        console.error('Error fetching featured:', err);
      }
    };
    fetchFeatured();
  }, []);

  useEffect(() => {
    const fetchCategories = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/admin/products/categories');
        setCategories(res.data);
      } catch (err) {
        console.error('Error fetching categories:', err);
      }
    };
    fetchCategories();
  }, []);

  const carouselSettings = {
    dots: true,
    infinite: true,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 3000,
    arrows: true,
  };

  return (
    <div className="home-container">
      {/* Carousel Section */}
      <section className="carousel-wrapper">
        <Slider {...carouselSettings}>
          {['Slide1.png', 'Slide2.png', 'Slide3.jpg'].map((img, index) => (
            <div key={index} className="carousel-slide">
              <img
                src={`/assests/${img}`}
                alt={`Slide ${index + 1}`}
                className="carousel-image"
              />
              <div className="carousel-overlay">
                <h1>Welcome to NatureNest</h1>
                <p>Discover, shop, and learn plant care from the experts.<br />Find the perfect plants for your home or garden, all in one place.<br />Expert tips, quality products, and beautiful greenery await you.</p>
                <a href="/catalog">
                  <button className="carousel-button">Shop Now</button>
                </a>
              </div>
            </div>
          ))}
        </Slider>
      </section>

    {/* Categories Section */}
      <section className="category-section">
        <h2>Shop by Category</h2>
        <div className="category-grid">
          {categories.map((cat, i) =>
            cat?.name ? (
              <a key={i} href={`/catalog?category=${cat.name.toLowerCase()}`} className="category-card">
                <img src={`http://localhost:5000/Uploads/${cat.imageUrl}`} alt={cat.name} />
                <h3>{cat.name} Plants</h3>
              </a>
            ) : null
          )}
        </div>
  */   </section>

      {/* Featured Plants Section */}
      <section className="featured-section">
        <h2>Featured Plants</h2>
        <div className="plant-grid">
          {featuredPlants.map((plant) => (
            <div className="plant-card" key={plant._id}>
              <img src={`http://localhost:5000/uploads/${plant.imageUrl}`} alt={plant.name} />
              <h3>{plant.name}</h3>
              <p>{plant.price}</p>
              <a href={`/product/${plant._id}`}>
                <button>View Details</button>
              </a>
            </div>
          ))}
        </div>
      </section>

      {/* Footer */}
      <footer className="footer">
        <p>&copy; {new Date().getFullYear()} NatureNest | All rights reserved 🌱</p>
      </footer>
    </div>
  );
};

export default Home;
